#include <vector>
#include <algorithm>

/**
 * Adaptive Hybrid Sort: Quicksort with Hoare partitioning and middle pivot.
 * Switches to insertion sort for partitions smaller than 16 elements.
 */
void adaptive_sort(std::vector<int>& arr) {
    int n = (int)arr.size();
    if (n < 2) return;
    bool asc = 1, desc = 1;
    for (int i = 1; i < n; i++) {
        if (arr[i] < arr[i - 1]) asc = 0;
        if (arr[i] > arr[i - 1]) desc = 0;
    }
    if (asc) return;
    if (desc) { std::reverse(arr.begin(), arr.end()); return; }
    struct S {
        static void q(std::vector<int>& v, int l, int h) {
            if (h - l < 24) {
                for (int i = l + 1; i <= h; i++) {
                    int x = v[i], j = i;
                    while (j > l && v[j - 1] > x) { v[j] = v[j - 1]; j--; }
                    v[j] = x;
                }
            } else {
                int m = l + (h - l) / 2, i = l - 1, j = h + 1;
                if (v[m] < v[l]) std::swap(v[m], v[l]);
                if (v[h] < v[l]) std::swap(v[h], v[l]);
                if (v[h] < v[m]) std::swap(v[h], v[m]);
                int p = v[m];
                while (1) {
                    while (v[++i] < p); while (v[--j] > p);
                    if (i >= j) break;
                    std::swap(v[i], v[j]);
                }
                q(v, l, j); q(v, j + 1, h);
            }
        }
    };
    S::q(arr, 0, n - 1);
}

